function solve(nums) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // The key insight is that if nums[a] is divisible by nums[b],
    // nums[a] can be replaced by nums[b]. This means nums[a] can effectively
    // become nums[b]. This process can cascade.
    // If x can become y, and y can become z, then x can become z.
    // The smallest possible value any element can become is the greatest common divisor
    // of some subset of numbers, but more specifically, it's related to the
    // smallest element that can divide it, transitively.

    // If an element x can be replaced by y, it means y divides x.
    // To minimize the sum, we want each element to become the smallest possible
    // divisor available in the set, which is the smallest number in the set
    // that can divide it, transitively.

    // Let S be the set of initial numbers.
    // If x in S can be replaced by y in S (i.e., y divides x), then x can become y.
    // This forms a directed graph where an edge exists from x to y if y divides x.
    // We want each node to reach its minimal reachable node.

    // Consider the set of all numbers that can divide some other number in the array.
    // The smallest possible value any element can be transformed into is the smallest
    // number present in the array that divides it, transitively.

    // Since the operation is: nums[a] <- nums[b] if nums[a] % nums[b] == 0.
    // The final value of nums[a] will be some original value nums[b_final]
    // such that nums[b_final] divides all the original values that could reach it,
    // or more simply, nums[b_final] divides the original nums[a].

    // Let G be the set of all unique values in nums.
    // We are looking for the smallest element v in G such that v divides x,
    // for every x in nums, provided such a chain of division exists.

    // The minimum value an element x can become is the smallest element y in the *original* nums
    // such that y divides x, AND y is reachable from x (i.e., there is a chain
    // x -> ... -> y where each step is a division).

    // A simpler perspective: If y divides x, and y is present, x can become y.
    // If y1 divides x, and y2 divides y1, then y2 divides x, and x can become y1, and y1 can become y2, so x can become y2.
    // This means an element x can become any element y in the set such that y divides x, AND y is reachable.

    // Reachability: If y divides x, and y is in nums, x can become y.
    // If x can become y, and z divides y, and z is in nums, then x can become z.

    // Let D be the set of all numbers in nums that can divide at least one other number in nums,
    // or themselves if they are the smallest possible divisor for some.

    // The final set of values will be a subset of the original values.
    // The smallest possible value for any element nums[i] is min({nums[j] | nums[j] divides nums[i] and j is reachable from i}).

    // Crucial Observation: If we have a set of numbers S, and we can reduce all elements to
    // the smallest common divisor D of a subset, D must be present in the set or be derived from it.
    // Since the operation only replaces with an existing number, the resulting values must be
    // chosen from the initial set of unique values.

    // Let U be the set of unique values in nums.
    // For any x in nums, the final value x' must be in U, and x' must divide x.
    // Furthermore, x' must be reachable from x.

    // Reachability Simplification: If y divides x, and y is in U, then x can become y.
    // If z divides y, and z is in U, then x can become z (via x->y->z).
    // Therefore, x can become any y in U such that y divides x, AND y is a "minimal divisor"
    // in the transitive closure of the division relation within U.

    // This boils down to finding, for each x in nums, the smallest element y in U such that y divides x.
    // Wait, this isn't quite right because the divisor must be present in the current array state.

    // Let's stick to the transitive closure:
    // Define a relation R on U: y R x if y divides x.
    // The set of reachable values for x is {y in U | y R x transitively}.
    // We want min_{y in Reachable(x)} y.

    // If y divides x, then x can be replaced by y.
    // If z divides y, then y can be replaced by z (if z is present).
    // If we keep applying this, x can become z.

    // Let's use dynamic programming/transitive closure on the unique elements U.
    const uniqueNums = Array.from(new Set(nums)).sort((a, b) => a - b);
    const uMap = new Map(); // value -> index in uniqueNums
    uniqueNums.forEach((val, index) => uMap.set(val, index));
    const m = uniqueNums.length;

    // smallestReachable[i] stores the smallest value in U that nums[uniqueNums[i]] can be reduced to.
    const smallestReachable = new Array(m).fill(null).map((_, i) => uniqueNums[i]);

    // Iterate through unique numbers in increasing order (since they are sorted)
    for (let i = 0; i < m; i++) {
        const currentVal = uniqueNums[i];

        // smallestReachable[i] is initialized to currentVal.
        // Now, check if currentVal can reduce any larger number j (j > i).
        // If j is divisible by currentVal, then j can be reduced to currentVal.
        for (let j = i + 1; j < m; j++) {
            const nextVal = uniqueNums[j];

            if (nextVal % currentVal === 0) {
                // nextVal can be reduced to currentVal.
                // Since currentVal is smaller than nextVal, this is a reduction.
                // We update smallestReachable[j] to be the minimum of its current value and currentVal.
                // Since we process in increasing order of currentVal, this naturally finds the smallest.
                smallestReachable[j] = Math.min(smallestReachable[j], currentVal);
            }
        }
    }

    // The loop above only handles direct reduction from larger elements to smaller elements present in U.
    // We need to account for transitivity: if x -> y and y -> z, then x -> z.
    // Since we process in increasing order, when considering uniqueNums[i] (the smaller value),
    // we can use its *final* smallest reachable value to update larger elements.

    // Let's refine the DP/relaxation approach.
    // smallestReachable[i] = smallest value v in U such that v divides uniqueNums[i] (transitively reachable).

    // Re-initialize:
    for (let i = 0; i < m; i++) {
        smallestReachable[i] = uniqueNums[i];
    }

    // We need multiple passes or a structure that handles the full transitive closure.
    // Since the graph is a DAG (due to division implies smaller/equal), we can iterate carefully.

    // A simpler relaxation approach over all pairs:
    let changed = true;
    while (changed) {
        changed = false;
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < m; j++) {
                if (i === j) continue;

                const valI = uniqueNums[i]; // Target element's initial value
                const valJ = uniqueNums[j]; // Divisor element's initial value

                // Check if valI can be reduced by valJ (i.e., valJ divides valI)
                if (valI % valJ === 0) {
                    // valI can be replaced by valJ.
                    // The current smallest reachable for valI is smallestReachable[i].
                    // The smallest reachable for valJ is smallestReachable[j].
                    // If valI -> valJ, then smallestReachable[i] must be <= smallestReachable[j].

                    // Since valI % valJ == 0, we know valJ divides valI.
                    // The smallest element reachable from valJ is smallestReachable[j].
                    // Since valI can become valJ, and valJ can become smallestReachable[j],
                    // valI can become smallestReachable[j].

                    const currentMinI = smallestReachable[i];
                    const potentialNewMinI = smallestReachable[j];

                    if (potentialNewMinI < currentMinI) {
                        smallestReachable[i] = potentialNewMinI;
                        changed = true;
                    }
                }
            }
        }
    }


    // Calculate the final sum
    let totalSum = 0;
    for (const num of nums) {
        // Find the index corresponding to num in uniqueNums
        const index = uMap.get(num);
        // The final value for this instance of 'num' is the smallest reachable value from it.
        totalSum += smallestReachable[index];
    }

    return totalSum;
}

