import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;

class Solution {
    public static long solve(long[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        // 1. Find unique elements and sort them
        Set<Long> uniqueSet = Arrays.stream(nums).boxed().collect(Collectors.toSet());
        Long[] uniqueNumsArray = uniqueSet.toArray(new Long[0]);
        Arrays.sort(uniqueNumsArray);

        int m = uniqueNumsArray.length;

        // Map value to its index in the sorted array
        Map<Long, Integer> uMap = new HashMap<>();
        for (int i = 0; i < m; i++) {
            uMap.put(uniqueNumsArray[i], i);
        }

        // smallestReachable[i] stores the minimum value in the original set 
        // that uniqueNumsArray[i] can be reduced to transitively.
        long[] smallestReachable = new long[m];
        for (int i = 0; i < m; i++) {
            smallestReachable[i] = uniqueNumsArray[i];
        }

        // 2. Compute transitive closure using relaxation (Floyd-Warshall-like approach on the divisibility DAG)
        // Since the values only decrease (or stay the same), we iterate until no further reduction is possible.
        boolean changed = true;
        while (changed) {
            changed = false;

            for (int i = 0; i < m; i++) { // Target element (uniqueNumsArray[i])
                for (int j = 0; j < m; j++) { // Divisor element (uniqueNumsArray[j])
                    if (i == j) continue;

                    long valI = uniqueNumsArray[i];
                    long valJ = uniqueNumsArray[j];

                    // If valJ divides valI, then valI can be replaced by valJ.
                    // If valI can become valJ, then the smallest reachable from valI
                    // can be at most the smallest reachable from valJ.
                    if (valI % valJ == 0) {
                        long potentialNewMinI = smallestReachable[j];

                        if (potentialNewMinI < smallestReachable[i]) {
                            smallestReachable[i] = potentialNewMinI;
                            changed = true;
                        }
                    }
                }
            }
        }

        // 3. Calculate the final sum
        long totalSum = 0;
        for (long num : nums) {
            int index = uMap.get(num);
            // For each original element, its final value is the smallest reachable value from its original value.
            totalSum += smallestReachable[index];
        }

        return totalSum;
    }
}
