        if (nums == null || nums.length == 0) {
            return 0;
        }

        // 1. Get unique sorted values
        Set<Long> uniqueSet = new TreeSet<>();
        for (long num : nums) {
            uniqueSet.add(num);
        }
        Long[] uniqueNumsArray = uniqueSet.toArray(new Long[0]);
        int m = uniqueNumsArray.length;

        // Map value to its index in the sorted unique array
        Map<Long, Integer> uMap = new HashMap<>();
        for (int i = 0; i < m; i++) {
            uMap.put(uniqueNumsArray[i], i);
        }

        // 2. Initialize smallestReachable
        // smallestReachable[i] stores the smallest value in the set that uniqueNumsArray[i] can be reduced to.
        long[] smallestReachable = new long[m];
        for (int i = 0; i < m; i++) {
            smallestReachable[i] = uniqueNumsArray[i];
        }

        // 3. Compute Transitive Closure (Relaxation)
        // Since the relationship (division) forms a DAG when viewed by value magnitude, 
        // we can iterate until no changes occur.
        boolean changed = true;
        while (changed) {
            changed = false;
