public class Solution {
    public static long solve(long[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        // 1. Get unique sorted elements
        Set<Long> uniqueSet = new TreeSet<>();
        for (long num : nums) {
            uniqueSet.add(num);
        }

        Long[] uniqueNums = uniqueSet.toArray(new Long[0]);
        int m = uniqueNums.length;

        // Map value to its index in uniqueNums
        Map<Long, Integer> uMap = new HashMap<>();
        for (int i = 0; i < m; i++) {
            uMap.put(uniqueNums[i], i);
        }

        // smallestReachable[i] stores the smallest value in U that uniqueNums[i] can be reduced to.
        // Initialize each element to itself.
        long[] smallestReachable = new long[m];
        for (int i = 0; i < m; i++) {
            smallestReachable[i] = uniqueNums[i];
        }

        // 2. Compute Transitive Closure / Relaxation (Floyd-Warshall style on the division graph)
        // Since the division graph is a DAG (only edges from larger to smaller), 
        // iterative relaxation will converge.

        boolean changed = true;
        while (changed) {
            changed = false;
            for (int i = 0; i < m; i++) { // Target node i (original value uniqueNums[i])
                for (int j = 0; j < m; j++) { // Divisor node j (original value uniqueNums[j])
