import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long solve(long[] nums) {
        if (nums == null || nums.length == 0) {
            return 0;
        }

        // 1. Find unique elements and sort them.
        Set<Long> uniqueSet = new HashSet<>();
        for (long num : nums) {
            uniqueSet.add(num);
        }
        Long[] uniqueArray = uniqueSet.toArray(new Long[0]);
        Arrays.sort(uniqueArray);

        int m = uniqueArray.length;

        // Map value to its index in the sorted unique array
        Map<Long, Integer> uMap = new HashMap<>();
        for (int i = 0; i < m; i++) {
            uMap.put(uniqueArray[i], i);
        }

        // smallestReachable[i] stores the smallest value in uniqueArray that uniqueArray[i] can be reduced to.
        long[] smallestReachable = new long[m];
        for (int i = 0; i < m; i++) {
            smallestReachable[i] = uniqueArray[i];
        }

        // 2. Compute the transitive closure using relaxation (Floyd-Warshall style logic, but tailored for division).
        // We iterate until no further reductions are possible.
        boolean changed = true;
        while (changed) {
            changed = false;
            // i represents the index of the element being reduced (the 'a' in the operation)
            for (int i = 0; i < m; i++) {
                // j represents the index of the divisor element (the 'b' in the operation)
                for (int j = 0; j < m; j++) {
                    if (i == j) continue;

                    long valI = uniqueArray[i]; // Original value at index i
                    long valJ = uniqueArray[j]; // Original value at index j

                    // Operation condition: nums[a] % nums[b] == 0
                    // Here, if valI is divisible by valJ, then valI can be replaced by valJ.
                    if (valI % valJ == 0) {

                        // Transitivity: If valI can become valJ, and valJ can become smallestReachable[j],
                        // then valI can become smallestReachable[j].
                        long potentialNewMinI = smallestReachable[j];
                        long currentMinI = smallestReachable[i];

                        if (potentialNewMinI < currentMinI) {
                            smallestReachable[i] = potentialNewMinI;
                            changed = true;
                        }
                    }
                }
            }
        }

        // 3. Calculate the final sum
        long totalSum = 0;
        for (long num : nums) {
            int index = uMap.get(num);
            // The final value for this instance of 'num' is the smallest reachable value from its original value.
            totalSum += smallestReachable[index];
        }

        return totalSum;
    }
}
