    // If z divides y, then y can be replaced by z (if z is present).
    // If we keep applying this, x can become z.

    // Let's use dynamic programming/transitive closure on the unique elements U.
    const uniqueNums = Array.from(new Set(nums)).sort((a, b) => a - b);
    const uMap = new Map(); // value -> index in uniqueNums
    uniqueNums.forEach((val, index) => uMap.set(val, index));
    const m = uniqueNums.length;

    // smallestReachable[i] stores the smallest value in U that nums[uniqueNums[i]] can be reduced to.
    const smallestReachable = new Array(m).fill(null).map((_, i) => uniqueNums[i]);

    // Iterate through unique numbers in increasing order (since they are sorted)
    for (let i = 0; i < m; i++) {
        const currentVal = uniqueNums[i];

        // smallestReachable[i] is initialized to currentVal.
        // Now, check if currentVal can reduce any larger number j (j > i).
        // If j is divisible by currentVal, then j can be reduced to currentVal.
        for (let j = i + 1; j < m; j++) {
            const nextVal = uniqueNums[j];

            if (nextVal % currentVal === 0) {
                // nextVal can be reduced to currentVal.
                // Since currentVal is smaller than nextVal, this is a reduction.
                // We update smallestReachable[j] to be the minimum of its current value and currentVal.
                // Since we process in increasing order of currentVal, this naturally finds the smallest.
                smallestReachable[j] = Math.min(smallestReachable[j], currentVal);
            }
        }
    }

    // The loop above only handles direct reduction from larger elements to smaller elements present in U.
    // We need to account for transitivity: if x -> y and y -> z, then x -> z.
    // Since we process in increasing order, when considering uniqueNums[i] (the smaller value),
    // we can use its *final* smallest reachable value to update larger elements.

    // Let's refine the DP/relaxation approach.
    // smallestReachable[i] = smallest value v in U such that v divides uniqueNums[i] (transitively reachable).

    // Re-initialize:
    for (let i = 0; i < m; i++) {
        smallestReachable[i] = uniqueNums[i];
    }

    // We need multiple passes or a structure that handles the full transitive closure.
    // Since the graph is a DAG (due to division implies smaller/equal), we can iterate carefully.

    // A simpler relaxation approach over all pairs:
    let changed = true;
    while (changed) {
        changed = false;
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < m; j++) {
                if (i === j) continue;

                const valI = uniqueNums[i]; // Target element's initial value
                const valJ = uniqueNums[j]; // Divisor element's initial value

                // Check if valI can be reduced by valJ (i.e., valJ divides valI)
                if (valI % valJ === 0) {
                    // valI can be replaced by valJ.
                    // The current smallest reachable for valI is smallestReachable[i].
                    // The smallest reachable for valJ is smallestReachable[j].
                    // If valI -> valJ, then smallestReachable[i] must be <= smallestReachable[j].

                    // Since valI % valJ == 0, we know valJ divides valI.
                    // The smallest element reachable from valJ is smallestReachable[j].
                    // Since valI can become valJ, and valJ can become smallestReachable[j],
                    // valI can become smallestReachable[j].

                    const currentMinI = smallestReachable[i];
                    const potentialNewMinI = smallestReachable[j];

                    if (potentialNewMinI < currentMinI) {
                        smallestReachable[i] = potentialNewMinI;
                        changed = true;
                    }
                }
            }
        }
    }


    // Calculate the final sum
    let totalSum = 0;
    for (const num of nums) {
        // Find the index corresponding to num in uniqueNums
        const index = uMap.get(num);
        // The final value for this instance of 'num' is the smallest reachable value from it.
        totalSum += smallestReachable[index];
    }

    return totalSum;
}
